#!/bin/bash

echo "=== Testing Jewelry Reorder API ==="
echo ""

# Configuration
API_URL="https://api.celorajewelry.com/api"
TOKEN="eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9..0cON_WfIi5Eq26n1jHpAlm9XFaqFW3tc3o91xei8B3Y"

echo "Step 1: Fetch current Earrings order"
echo "--------------------------------------"
curl -s -X POST "$API_URL/jewelry/search" \
  -H 'Content-Type: application/json' \
  --data-raw '{
    "jewelryType": "Earrings",
    "sortBy": "sequence",
    "sortOrder": "asc"
  }' | jq -r '.data[] | "\(.sequence) - \(.title) (\(.jewelryId))"' | head -10

echo ""
echo "Step 2: Test reordering - Move item to first position"
echo "------------------------------------------------------"

# Get the third item's ID
THIRD_ITEM_ID=$(curl -s -X POST "$API_URL/jewelry/search" \
  -H 'Content-Type: application/json' \
  --data-raw '{
    "jewelryType": "Earrings",
    "sortBy": "sequence",
    "sortOrder": "asc",
    "limit": 3
  }' | jq -r '.data[2].jewelryId')

echo "Moving item: $THIRD_ITEM_ID to position 0"

curl -s -X PUT "$API_URL/jewelry/$THIRD_ITEM_ID" \
  -H 'Content-Type: application/json' \
  -H "Authorization: Bearer $TOKEN" \
  --data-raw '{"newIndex": 0}' | jq '{jewelryId, title, sequence, jewelryType}'

echo ""
echo "Step 3: Verify new order"
echo "------------------------"
sleep 1
curl -s -X POST "$API_URL/jewelry/search" \
  -H 'Content-Type: application/json' \
  --data-raw '{
    "jewelryType": "Earrings",
    "sortBy": "sequence",
    "sortOrder": "asc"
  }' | jq -r '.data[] | "\(.sequence) - \(.title) (\(.jewelryId))"' | head -10

echo ""
echo "=== Test Complete ==="
